def composition(layoutA, layoutB):
    """Return the layout equivalent to applying layoutB, then layoutA."""
    # Case 1: layoutB is None
    if layoutB is None:
        return layoutA

    # Case 2: layoutB is an integer
    if is_int(layoutB):
        layoutB = Layout(layoutB)

    # Case 5: stride-zero layoutB
    if is_layout(layoutB) and layoutB.stride == 0 or (is_tuple(layoutB.stride) and all(s == 0 for s in flatten(layoutB.stride))):
        return Layout(layoutB.shape, 0)

    # Case 3: layoutB is a tuple (tree of modes, None entries are no-ops)
    # This handles composition when B specifies mode-to-mode mapping
    if is_tuple(layoutB):
        assert is_layout(layoutA) and is_tuple(layoutA.shape), "layoutA must be hierarchical for tuple layoutB"
        # Match B entries with A's modes, None means keep A's mode
        new_modes = []
        for mode_idx, b_entry in enumerate(layoutB):
            if mode_idx < len(layoutA.shape):
                if b_entry is None:
                    new_modes.append(layoutA[mode_idx])
                else:
                    new_modes.append(composition(layoutA[mode_idx], b_entry))
            elif b_entry is not None:
                new_modes.append(composition(Layout(1), b_entry))
        return make_layout(*new_modes)

    # Now layoutB is a Layout object
    assert is_layout(layoutB), f"layoutB must be Layout, got {type(layoutB)}"

    # Case 4: hierarchical shape (rank > 1)
    if is_tuple(layoutB.shape):
        # Compose each mode of layoutA with each mode of layoutB
        # and combine results with make_layout
        a_rank = len(layoutA.shape) if is_tuple(layoutA.shape) else 1
        b_rank = len(layoutB.shape)

        # Handle different rank scenarios
        if a_rank == 1:
            # A is rank-1, B is rank-N: compose and flatten to match
            # The result should be rank-N or collapsed
            # Use the general rank-1 handling but with B flattened
            return composition(layoutA, Layout(flatten(layoutB.shape), flatten(layoutB.stride)))
        else:
            # Both have ranks > 1
            # Align ranks by padding if necessary
            a_modes = [layoutA[i] for i in range(a_rank)] if a_rank > 1 else [layoutA]
            b_modes = [layoutB[i] for i in range(b_rank)]

            # Pad with 1-size identity layouts if ranks differ
            while len(a_modes) < len(b_modes):
                a_modes.append(Layout(1))
            while len(b_modes) < len(a_modes):
                b_modes.append(Layout(1))

            composed = [composition(a, b) for a, b in zip(a_modes, b_modes)]
            return make_layout(*composed)

    # Case 6: general rank-1 layoutB
    # First check if B is effectively rank-1 (single component)
    if not is_tuple(layoutB.shape):
        # B is rank-1
        # The key: R(i) = A(B(i))
        # Result shape = B.shape
        # Result stride = A(B(1)) - A(B(0)) (for linear cases)

        N = size(layoutB)
        if N == 0:
            return Layout(0, 0)
        if N == 1:
            # Single element, stride doesn't matter
            return Layout(N, 0)

        # Compute stride of result: A(B(1)) - A(B(0))
        # B(0) and B(1) are linear indices from B's stride
        # For B = shape:S, B(0)=0, B(1)=S
        b_stride = layoutB.stride

        # To compute A(B(1)), we need to understand how A handles
        # a linear input equal to b_stride

        # Use crd2idx to map b_stride through A
        val0 = layoutA(0) if N > 0 else 0
        val1 = layoutA(b_stride) if N > 1 else 0

        result_stride = val1 - val0 if N > 1 else 0

        # Result shape inherits from B
        result_shape = layoutB.shape

        # For nested stride from B, we need to handle it
        if is_tuple(result_shape):
            return Layout(flatten(result_shape), flatten(result_stride))

        return Layout(result_shape, result_stride)

    # Fallback - just return layoutA for now
    return layoutA
